$repoRoot = "C:\Users\mylr1\GEOX"
$patchRoot = Join-Path $repoRoot "_patch_ops1_backup_restore_minimal"
if (Test-Path $patchRoot) { Remove-Item -Recurse -Force $patchRoot }
New-Item -ItemType Directory -Force -Path $patchRoot | Out-Null
$files = @(
  @{ Path = 'backup_db.ps1'; Base64 = @'

'@ },
  @{ Path = 'backup_evidence.ps1'; Base64 = @'

'@ },
  @{ Path = 'restore_db.ps1'; Base64 = @'

'@ },
  @{ Path = 'restore_evidence.ps1'; Base64 = @'

'@ },
  @{ Path = 'acceptance/sprintOps1/README_sprintOps1_acceptance.md'; Base64 = @'

'@ },
  @{ Path = 'acceptance/sprintOps1/ACCEPTANCE_sprintOps1_backup_restore_minimal.ps1'; Base64 = @'

'@ },
  @{ Path = 'docs/delivery/GEOX_Operations_Runbook_v1.md'; Base64 = @'

'@ }
)
foreach ($f in $files) {
  $outPath = Join-Path $patchRoot $f.Path
  $dir = Split-Path -Parent $outPath
  if (-not [string]::IsNullOrWhiteSpace($dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  [System.IO.File]::WriteAllBytes($outPath, [Convert]::FromBase64String(($f.Base64 -replace "`r|`n", "")))
}
$zipPath = Join-Path (Split-Path $repoRoot -Parent) "GEOX_patch_ops1_backup_restore_minimal_regenerated.zip"
if (Test-Path $zipPath) { Remove-Item -Force $zipPath }
Compress-Archive -Path (Join-Path $patchRoot "*") -DestinationPath $zipPath -CompressionLevel Optimal
Write-Host "DONE: $zipPath"
